import { Effect, Context, Layer, Data, pipe } from "effect";

interface Req { readonly url: string; readonly params: Record<string, string> }
const Req = Context.GenericTag<Req>("web/Req");

interface User { readonly id: string; readonly name: string }
class UserNotFound extends Data.TaggedError("UserNotFound")<{ readonly id: string }> {}

interface DB { readonly findUser: (id: string) => Effect.Effect<User, UserNotFound> }
const DB = Context.GenericTag<DB>("web/DB");

const handler: Effect.Effect<{ status: number; body: string }, UserNotFound, Req | DB> =
  Effect.gen(function* () {
    const req = yield* Req;
    const db = yield* DB;
    const id = req.params.id ?? "";
    const user = yield* db.findUser(id);
    return { status: 200, body: user.name };
  });

const ReqLive = Layer.succeed(Req, { url: "/users/42", params: { id: "42" } });
const DBLive = Layer.succeed(DB, {
  findUser: (id) => Effect.succeed({ id, name: "Ada" }),
});

// Dependency direction: handler <- (Req, DB)
const AppLive = Layer.mergeAll(ReqLive, DBLive);
export const program = pipe(handler, Effect.provide(AppLive));
